extern char *str_dup(const char *s);
if (!s) return str_dup("");
size_t cap = strlen(s) + 1;
char *out = (char *)malloc(cap);
if (!out) return NULL;
size_t oi = 0;
int in_ws = 0;
for (size_t i = 0; s[i]; i++) {
    char c = s[i];
    if (c == ' ' || c == '\t' || c == '\n' || c == '\r') {
        if (!in_ws && oi > 0) { out[oi++] = ' '; in_ws = 1; }
    } else {
        out[oi++] = c;
        in_ws = 0;
    }
}
while (oi > 0 && out[oi - 1] == ' ') oi--;
out[oi] = '\0';
return out;
